"""Per-lemma inflection model for Crimean Tatar.

Learns each lemma's harmony/voicing/linking profile from training, then predicts
any (lemma, feature) form. Used to generate a lexicon FST that covers every known
lemma across all feature combinations (including unseen lemma+feature combos).
"""
import collections

BACK_V = set('aıouUâ'); FRONT_V = set('eiöüİ'); VOWELS = BACK_V | FRONT_V
VOICELESS = set('pçtkqsşfhÇ')

NOUN_CASES = ['NOM', 'ACC', 'GEN', 'DAT', 'ABL', 'LOC']
VERB_FEATS = ['NFIN', 'IMP;SG;2', 'SG;3;PRS', 'SG;3;PST']

def last_vowel(s):
    for c in reversed(s):
        if c in VOWELS:
            return c
    return None

def _suffix(lem, wf):
    i = 0
    while i < len(lem) and i < len(wf) and lem[i] == wf[i]:
        i += 1
    return wf[i:]

class Model:
    def __init__(self, rows):
        # rows: list of (lemma, wordform, feat)
        self.gold = {}                       # (lemma, feat) -> wordform (observed)
        self.pos = {}                        # lemma -> N/ADJ/V
        self.h = collections.defaultdict(collections.Counter)   # harmony votes
        self.dt = collections.defaultdict(collections.Counter)  # abl/loc d vs t
        self.g = collections.defaultdict(collections.Counter)   # dat voiced vs voiceless
        self.link = collections.defaultdict(collections.Counter)  # linking-n
        for lem, wf, feat in rows:
            self.gold[(lem, feat)] = wf
            parts = feat.split(';')
            self.pos[lem] = parts[0]
            case = parts[-1]
            suf = _suffix(lem, wf)
            fv = [c for c in suf if c in VOWELS]
            if case not in ('NOM', 'NFIN') and fv:
                self.h[lem]['F' if fv[0] in FRONT_V else 'B'] += 1
            if case in ('ABL', 'LOC') and suf:
                self.dt[lem]['t' if suf[0] == 't' else ('n' if suf[0] == 'n' else 'd')] += 1
            if case == 'DAT' and suf:
                self.g[lem]['q' if suf[0] in 'qk' else ('n' if suf[0] == 'n' else 'g')] += 1
            # linking-n: oblique case marker preceded by epenthetic n after a vowel-final stem
            if case in ('DAT', 'LOC', 'ABL') and suf.startswith('n'):
                self.link[lem]['Y'] += 1
            elif case in ('DAT', 'LOC', 'ABL') and suf:
                self.link[lem]['N'] += 1

    def harm(self, lem):
        if self.h.get(lem):
            return self.h[lem].most_common(1)[0][0]
        return 'B' if last_vowel(lem) in BACK_V else 'F'

    def _voiceless_dt(self, lem):
        if self.dt.get(lem):
            top = self.dt[lem].most_common(1)[0][0]
            if top != 'n':
                return top == 't'
        return lem[-1] in VOICELESS

    def _voiceless_g(self, lem):
        if self.g.get(lem):
            top = self.g[lem].most_common(1)[0][0]
            if top != 'n':
                return top == 'q'
        return lem[-1] in VOICELESS

    def _linking(self, lem):
        if self.link.get(lem):
            return self.link[lem].most_common(1)[0][0] == 'Y'
        return False

    def predict(self, lem, feat, use_gold=True):
        if use_gold and (lem, feat) in self.gold:
            return self.gold[(lem, feat)]
        parts = feat.split(';')
        pos = parts[0]
        case = parts[-1]
        h = self.harm(lem)
        if pos in ('N', 'ADJ'):
            if case == 'NOM':
                return lem
            link = self._linking(lem)
            if case == 'ACC':
                return lem + ('nı' if h == 'B' else 'ni')
            if case == 'GEN':
                return lem + ('nıñ' if h == 'B' else 'niñ')
